const input = $input.first();

const binaries = input.binary || {};

const output = [];

for (const key of Object.keys(binaries)) {

    output.push({
        json: {
            jobDescription: input.json.jobDescription,
            email: input.json.email,
            fileName: binaries[key].fileName
        },
        binary: {
            data: binaries[key]
        }
    });

}

return output;

const items = $input.all();

const output = [];

for (const item of items) {

    let text = item.json.output;

    // Remove markdown if present
    text = text.replace(/```json/g, "");
    text = text.replace(/```/g, "");
    text = text.trim();

    try {

        const parsed = JSON.parse(text);

        output.push({
            json: parsed
        });

    } catch (error) {

        output.push({
            json: {
                error: "Invalid JSON returned by AI",
                raw: text
            }
        });

    }

}

return output;

const items = $input.all();

items.sort((a, b) => b.json.score - a.json.score);

const medals = ["🥇", "🥈", "🥉"];

return items.map((item, index) => ({
  json: {
    ...item.json,
    rank: index + 1,
    medal: medals[index] || "🏅"
  }
}));

